ga3Y(){return"\ub2e4\uc774\ube0c\ub85c \ud2b8\ub808\uc774\ub108\ub294 \ud6c8\ub828 \uae30\ub85d\uc744 \uc774 \uae30\uae30 \uc548\uc5d0\ub9cc \uc800\uc7a5\ud574\uc694. \uacc4\uc815\ub3c4, \uc11c\ubc84\ub3c4 \uc5c6\uc5b4\uc694.\n\n\uc2ec\ubc15\xb7\uc218\uc2ec \uac19\uc740 \uac74\uac15 \ub370\uc774\ud130\ub294 \uc774 \uc6f9 \ubc84\uc804\uc5d0\uc11c \uc218\uc9d1\ud558\uc9c0 \uc54a\uc544\uc694. \ud6c8\ub828 \uc2dc\uac04\uacfc \ucee8\ud2b8\ub799\uc158 \uae30\ub85d\uc740 \ube0c\ub77c\uc6b0\uc800 \ub85c\uceec \uc800\uc7a5\uc18c(IndexedDB)\uc5d0\ub9cc \ub0a8\uace0, \ube0c\ub77c\uc6b0\uc800 \ub370\uc774\ud130\ub97c \uc9c0\uc6b0\uba74 \ud568\uaed8 \uc0ac\ub77c\uc838\uc694. \uae30\ub85d\uc744 \uc9c0\ud0a4\uace0 \uc2f6\uc73c\uba74 \uc124\uc815\uc774 \uc544\ub2cc \ud788\uc2a4\ud1a0\ub9ac \ud654\uba74\uc5d0\uc11c JSON\uc73c\ub85c \ub0b4\ubcf4\ub0b4 \ub450\uc138\uc694.\n\n\uc81c3\uc790\uc5d0\uac8c \uc5b4\ub5a4 \ub370\uc774\ud130\ub3c4 \uc804\uc1a1\ud558\uc9c0 \uc54a\uc544\uc694."},
ga53(){return"\ub2e4\uc774\ube0c\ub85c \ud2b8\ub808\uc774\ub108\ub294 \ud504\ub9ac\ub2e4\uc774\ube59 \uc2a4\ud0dc\ud2f1(\uc228\ucc38\uae30)\uc744 \ubb3c \ubc16(\ub4dc\ub77c\uc774)\uc5d0\uc11c \uc5f0\uc2b5\ud558\uae30 \uc704\ud55c \ud6c8\ub828 \ubcf4\uc870 \ub3c4\uad6c\uc608\uc694.\n\n\uc774 \uc571\uc740 \uc758\ub8cc \uae30\uae30\uac00 \uc544\ub2c8\uace0, \uc548\uc804\uc744 \ubcf4\uc7a5\ud558\uc9c0 \uc54a\uc544\uc694. \uc228\ucc38\uae30 \ud6c8\ub828\uc5d0\ub294 \ube14\ub799\uc544\uc6c3 \uc704\ud5d8\uc774 \uc788\uc5b4\uc694. \uc800\ub3c4 \ud56d\uc0c1 \uc549\uc544\uc11c, \ubb3c \ubc16\uc5d0\uc11c, \ubb34\ub9ac\ud558\uc9c0 \uc54a\uace0 \ud574\uc694. \uc5b4\uc9c0\ub7fd\uac70\ub098 \uc774\uc0c1\ud558\uba74 \ubc14\ub85c \uba48\ucdb0\uc8fc\uc138\uc694.\n\n\ubb3c\uc18d\xb7\uc695\uc870\uc5d0\uc11c\ub294 \uc808\ub300 \uc0ac\uc6a9\ud558\uc9c0 \ub9c8\uc138\uc694. \uc774 \uc571\uc744 \uc0ac\uc6a9\ud574 \ubc1c\uc0dd\ud55c \uacb0\uacfc\uc5d0 \ub300\ud55c \ucc45\uc784\uc740 \uc0ac\uc6a9\uc790 \ubcf8\uc778\uc5d0\uac8c \uc788\uc5b4\uc694."},
