ga29(){return"\ud504\ub9ac\ub2e4\uc774\ube59 \uc2a4\ud0dc\ud2f1\uc774 \ucc98\uc74c\uc774\ub77c\uba74"},
ga2a(){return"CO2\xb7O2 \ud14c\uc774\ube14\uc774 \ubb54\uc9c0, \uc65c \uc228\ucc38\uae30\uac00 \ub290\ub294\uc9c0 3\ubd84\uc774\uba74 \uc774\ud574\ub3fc\uc694"},
gPC(){return"\ud6c8\ub828 \uac00\uc774\ub4dc"},
gOI(){return"\uc2a4\ud0dc\ud2f1 \ud6c8\ub828\uc774 \ubb50\uc608\uc694?"},
gOH(){return"\uc2a4\ud0dc\ud2f1(STA)\uc740 \uc6c0\uc9c1\uc774\uc9c0 \uc54a\uace0 \uc228\uc744 \ucc38\ub294 \ud504\ub9ac\ub2e4\uc774\ube59 \uc885\ubaa9\uc774\uc5d0\uc694. \uc774 \uc571\uc740 \ubb3c \ubc16\uc5d0\uc11c(\ub4dc\ub77c\uc774) \ud3b8\ud558\uac8c \uc549\uc544 \uc228\ucc38\uae30\ub97c \uc5f0\uc2b5\ud558\ub294 \ud6c8\ub828 \ub3c4\uad6c\uc608\uc694.\n\n\uc228\uc744 \ucc38\ub2e4 \ubcf4\uba74 \ub2f5\ub2f5\ud55c \ub290\ub08c\uacfc \ud568\uaed8 \ubc30\uac00 \uafc0\ub801\uc774\ub294 \ud6a1\uaca9\ub9c9 \uc218\ucd95\uc774 \uc640\uc694. \uc774\uac74 \uc0b0\uc18c\uac00 \ubc14\ub2e5\ub098\uc11c\uac00 \uc544\ub2c8\ub77c, \ubab8\uc5d0 \uc774\uc0b0\ud654\ud0c4\uc18c(CO2)\uac00 \uc313\uc774\uba74\uc11c '\uc228 \uc26c\uc5b4!' \ud558\uace0 \ubcf4\ub0b4\ub294 \uc2e0\ud638\uc608\uc694. \ud6c8\ub828\uc740 \uc774 \uc2e0\ud638\ub97c \uacac\ub514\uace0 \ubab8\uc744 \uc774\uc644\ud558\ub294 \uc5f0\uc2b5\uc774\uc5d0\uc694.\n\n\uc800\ub3c4 \uc655\ucd08\ubcf4 \ub54c\ub294 1\ubd84\ub3c4 \ubc84\uac70\uc6e0\uc5b4\uc694. \ub9e4\uc77c \uc870\uae08\uc529, \ubb34\ub9ac\ud558\uc9c0 \uc54a\uace0 \uc313\uc73c\uba74 \ub298\uc5b4\uc694."},
